export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:12。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "行政組在主樓二樓。門是磨砂玻璃的，上面貼著黃銅名牌：「行政組／場地調度／門禁管理」。透過門上的小窗，能看見裡面一張木質櫃台，一個工作人員坐在後面，旁邊的木盒裡掛著一排鑰匙和卡片。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在走廊轉角處。樓梯間在他身後，行政組的門在他右前方。距離大概十五步。看得見，聽不見。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠站在走廊另一頭的窗邊。她手裡拿著一張校慶流程表，假裝在看。相機掛在脖子上，鏡頭蓋沒有摘。她在用餘光盯著行政組的門。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她來了。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有說要來。但她來了。她在自己看。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這比我想像的順。她說「不要靠近我」，但她自己站到了能看到行政組的位置。她在驗證。她比我更想確認。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:13。行政組的門開了。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個穿深藍色背心的工作人員走出來，手裡拿著一本厚厚的登記冊。他把登記冊放在門口的矮櫃上，翻開，從口袋裡掏出一支筆。然後他轉身回辦公室裡，過了幾秒，捧著一個木製卡片盒出來。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）登記本。卡片盒。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）就是現在。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "工作人員把卡片盒放在登記冊旁邊。他低頭翻盒裡的卡片——每張卡片上印著樓層和區域名稱，裝在透明塑膠套裡。他的手指一張一張地翻過去，翻到某一張時停了。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）南翼。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在找南翼備用門禁卡。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "工作人員抽出那張卡，放在登記冊上。他翻開冊子，找到空白行，開始寫。顧言離得太遠，看不清字。但他看得見那張卡的顏色——白底紅框，和普通門禁卡不一樣。備用卡。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊另一頭，一聲極輕的快門。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她拍了。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的流程表擋在相機前面。她沒有舉起相機——她把鏡頭蓋打開，相機掛在胸前，用流程表遮住手的位置，按了一次快門。從外面看，她只是一個在看流程表的學生。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯熟練。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她做過很多次了。不是第一次用這種方式拍照。她在調查這件事。一直在調查。在我還不知道她是誰的時候，她就已經開始了。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "工作人員寫完登記，把卡片遞給從樓梯間上來的一個保安人員。保安接過卡，點了一下頭，往南翼方向走了。工作人員合上登記冊，端著卡片盒回了辦公室。門關上。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊恢復安靜。雨打窗戶。日光燈嗡嗡響。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:15。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從窗邊走過來。她沒有走到顧言面前——她在離他三步的地方停下。這是她的距離。精確的。不近不遠。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "第二件。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把流程表摺起來，塞進攝影背心的口袋。相機的鏡頭蓋已經重新蓋上了。一切恢復原樣。像什麼都沒發生過。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你說你死在醫務室那次。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯第三輪。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "也跟南翼門禁有關。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。是陳述。她在用她的方式確認——把他的記憶變成她調查筆記裡的一行。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她把南翼門禁卡和我第三輪的死連起來了。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第三輪。我利用邵叔的保護待在醫務室。南翼走廊。門從外面鎖上。藥少了。監控空白。被隔離。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）南翼。門禁。鎖門的人需要門禁權限。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她不需要我說細節。她只需要確認關聯存在。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沉默了一會兒。雨聲填滿了那段空白。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "兩件。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你說的不是巧合。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在承認。不是相信我——是承認這些事之間有聯繫。林主任封照片區、南翼門禁卡借出——她知道這些意味著什麼。她本來就在查這條線。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我只是比她早知道了今天的結果。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "12:30。裝卸區。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "第三件。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "如果也中——", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我聽你說。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉身。走了兩步，又停。沒有回頭。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不要跟著我。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "好。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲往樓梯間去了。門開、門關。走廊裡只剩日光燈的嗡鳴和雨打玻璃的聲音。", background: Background.Chapter_6_Ch6_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）兩件。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她說「不是巧合」。她開始認真對待了。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但她沒有放鬆警惕。「不要跟著我」——她在保持距離。她在控制節奏。她要看第三件是不是也中，才會真正打開一條縫。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯第三件是最難的。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）12:30。裝卸區。空相機包。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那個包和她有關。她聽到「空的」的時候動了。如果第三件也中——她不只是在驗證我能預測今天的事。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在驗證我見過什麼。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她要確定我是真的看過那個人打開包、說過那句話。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯而那個人做的事情，和她有關。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）12:30。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）等。", background: Background.Chapter_6_Ch6_Act4_S0, portrait: Portrait.GuYan_Determined },
];
